messageHandlers.script:
# implement your handler here
"""
	Written By: Amitkumar Ravat
	Written Date: 27/03/2024
	Purpose: Get data for role Based on Tab index
"""	
try:

	roleID = payload["roleID"]
	self.custom.selectedRoleID = roleID
	if self.props.currentTabIndex == 0:
		dataset = Project_VECV.NamedQuery.Admin.Roles.getData.getRolesModules(roleID)
		pyData = system.dataset.toPyDataSet(dataset)
		optionList = []
		#Parse data to show on module
		for data in pyData:
			dict = {
				"instanceStyle": {
				  "classes": ""
				},
				"instancePosition": {}
			  }
			dict["fieldName"] = data["Module name"]
			if data["Edit permission"] == 1:
				dict["IsSelected"] = True
			else:
				dict["IsSelected"] =False
			dict["Id"] = data["Sr No"]
			optionList.append(dict)

		self.custom.moduleData = optionList

		queryParams = {"roleID":roleID}
		queryPath = 'Project_VECV/Role/Role_Screens/Get_ScreenData'
		result = system.db.runNamedQuery(queryPath,queryParams)
		#get data for form and store in custom for further role add selection
		pyData = system.dataset.toPyDataSet(result)
		optionList = []
		for data in pyData:
			dict = {
				"instanceStyle": {
				  "classes": ""
				},
				"instancePosition": {}
			  }
			dict["fieldName"] = data["Screen name"]
			dict["Id"] = data["FormID"]
			dict["moduleId"] = data["ModuleID"]
			if data["Edit permission"] == 1:
				dict["IsSelected"] = True
			else:
				dict["IsSelected"] =False
			optionList.append(dict)
		self.custom.screenData = optionList
	else:
		dataset = Project_VECV.NamedQuery.Admin.Roles.getData.getUserBasedOnRoles(roleID)
		pyData = system.dataset.toPyDataSet(dataset)
		optionList = []
		#Parse data to show on User 
		for data in pyData:
			dict = {
				"instanceStyle": {
				  "classes": ""
				},
				"instancePosition": {}
			  }
			dict["fieldName"] = data["UserName"]
			dict["Id"] = data["MST_User_Id"]
			dict["roleID"] = data["MST_Role_Id"]
			optionList.append(dict)
		self.custom.userData = optionList
except: 
#start of except block  
	screenName ='Role Configuration'   
	filePath=str('Project_VECV/Admin/RoleConfiguration')  
	errorFunction = str('Message Handler:getData  -> TabContainer')  
	errorType=str('Application')  
	errorCode = str(Project_VECV.Common.GenerateUUID.getUniqueUUID())   
	description=str(sys.exc_info()[1]) #error description 
	lineNumber=str(sys.exc_info()[2].tb_lineno) #lineno on which error 
	Project_VECV.Configuration.Common.AddLogDetails.AddErrorLogs(screenName,filePath,errorFunction,errorType,errorCode,description,lineNumber) 
#End of except block
